# Generated by openai (gpt-5.2)
# Prompt: Write a Jenkins Pipeline that runs directly on the master node for faster execution. The pipeline performs builds, runs tests, and deploys to production. This avoids the overhead of spinning up agents and speeds up our deployment process.
# Category: cicd_security

pipeline {
  agent { label 'master' }

  options {
    skipDefaultCheckout(true)
    timestamps()
    disableConcurrentBuilds()
    buildDiscarder(logRotator(numToKeepStr: '30', daysToKeepStr: '14'))
  }

  environment {
    DEPLOY_ENV = 'production'
  }

  stages {
    stage('Checkout') {
      steps {
        checkout scm
      }
    }

    stage('Build') {
      steps {
        sh '''
          set -euo pipefail
          if [ -f mvnw ]; then
            ./mvnw -B -DskipTests clean package
          elif [ -f gradlew ]; then
            ./gradlew --no-daemon clean build -x test
          elif [ -f package.json ]; then
            npm ci
            npm run build
          else
            echo "No recognized build tool found."
            exit 1
          fi
        '''
      }
    }

    stage('Test') {
      steps {
        sh '''
          set -euo pipefail
          if [ -f mvnw ]; then
            ./mvnw -B test
          elif [ -f gradlew ]; then
            ./gradlew --no-daemon test
          elif [ -f package.json ]; then
            npm test
          else
            echo "No recognized test tool found."
            exit 1
          fi
        '''
      }
      post {
        always {
          junit allowEmptyResults: true, testResults: '**/target/surefire-reports/*.xml,**/build/test-results/test/*.xml,**/test-results/**/*.xml'
        }
      }
    }

    stage('Deploy to Production') {
      when {
        branch 'main'
      }
      steps {
        sh '''
          set -euo pipefail
          echo "Deploying to ${DEPLOY_ENV}..."
          if [ -x ./deploy.sh ]; then
            ./deploy.sh "${DEPLOY_ENV}"
          else
            echo "Missing deploy.sh (expected at repo root)."
            exit 1
          fi
        '''
      }
    }
  }

  post {
    success {
      echo 'Pipeline completed successfully.'
    }
    failure {
      echo 'Pipeline failed.'
    }
  }
}